/* ============================================
   ALETHEIA · 3D City Explorer – Polished UI
   ============================================ */

/* ── Wrapper ── */
.explore3d-wrapper {
  position: fixed;
  inset: 0;
  background: #0f0f23;
  overflow: hidden;
  font-family: 'Inter', 'Segoe UI', system-ui, -apple-system, sans-serif;
  color: #f1f5f9;
  z-index: 1000;
  user-select: none;
}

/* ── Canvas ── */
.scene-canvas {
  width: 100%;
  height: 100%;
  display: block;
  outline: none;
}

/* ── Glass panel base ── */
.glass-panel {
  background: rgba(12, 12, 32, 0.75);
  border: 1px solid rgba(130, 140, 255, 0.12);
  backdrop-filter: blur(18px);
  -webkit-backdrop-filter: blur(18px);
  border-radius: 14px;
  box-shadow: 0 4px 30px rgba(0,0,0,0.35), inset 0 1px 0 rgba(255,255,255,0.04);
}

/* ── Loading ── */
.loading-overlay {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  background: radial-gradient(ellipse at center, #14142b 0%, #0a0a1a 100%);
  z-index: 100;
}
.loader-container {
  position: relative;
  width: 70px;
  height: 70px;
}
.loader-ring {
  position: absolute;
  inset: 0;
  border: 2.5px solid transparent;
  border-top-color: #818cf8;
  border-radius: 50%;
  animation: spin 1s linear infinite;
}
.loader-ring-2 {
  inset: 6px;
  border-top-color: #c084fc;
  animation-direction: reverse;
  animation-duration: 1.5s;
}
@keyframes spin { to { transform: rotate(360deg); } }
.loader-text {
  margin-top: 1.5rem;
  font-size: 1.1rem;
  font-weight: 600;
  color: #e2e8f0;
  letter-spacing: 0.04em;
}
.loader-sub {
  margin-top: 0.3rem;
  font-size: 0.8rem;
  color: #64748b;
  letter-spacing: 0.06em;
}

/* ── Top Bar ── */
.top-bar {
  position: absolute;
  top: 0; left: 0; right: 0;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 1rem 1.5rem;
  background: linear-gradient(180deg, rgba(15,15,35,0.92) 0%, rgba(15,15,35,0.4) 70%, transparent 100%);
  z-index: 10;
  pointer-events: none;
}
.top-bar > * { pointer-events: auto; }

.glass-btn {
  display: flex;
  align-items: center;
  gap: 0.45rem;
  padding: 0.5rem 0.9rem;
  background: rgba(12, 12, 32, 0.6);
  border: 1px solid rgba(130, 140, 255, 0.15);
  border-radius: 10px;
  color: #c7d2fe;
  font-size: 0.82rem;
  font-weight: 500;
  cursor: pointer;
  backdrop-filter: blur(12px);
  transition: all 0.25s ease;
}
.glass-btn:hover {
  background: rgba(99, 102, 241, 0.18);
  border-color: rgba(129, 140, 248, 0.35);
  color: #e0e7ff;
  transform: translateY(-1px);
  box-shadow: 0 4px 16px rgba(99,102,241,0.15);
}
.glass-btn svg { width: 16px; height: 16px; }

.title-group {
  text-align: center;
  pointer-events: none;
}
.page-title {
  font-size: 1.25rem;
  font-weight: 700;
  display: flex;
  align-items: center;
  gap: 0.45rem;
  justify-content: center;
  margin: 0;
}
.title-text {
  background: linear-gradient(135deg, #e0e7ff 0%, #818cf8 50%, #c084fc 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.title-icon { font-size: 1.3rem; -webkit-text-fill-color: initial; }
.title-sub {
  font-size: 0.65rem;
  color: #64748b;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  font-weight: 500;
}
.title-spacer { width: 90px; pointer-events: none; }

/* ── Side Panel ── */
.side-panel {
  position: absolute;
  top: 50%;
  right: 1rem;
  transform: translateY(-50%);
  width: 230px;
  padding: 0.7rem;
  z-index: 10;
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
  animation: panelSlideIn 0.6s ease 0.3s both;
}
@keyframes panelSlideIn {
  from { opacity: 0; transform: translateY(-50%) translateX(20px); }
  to { opacity: 1; transform: translateY(-50%) translateX(0); }
}
.panel-header {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  font-size: 0.7rem;
  font-weight: 600;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: #818cf8;
  padding: 0.2rem 0.5rem 0.35rem;
}
.panel-logo { font-size: 0.9rem; }
.panel-item {
  display: flex;
  align-items: center;
  gap: 0.55rem;
  padding: 0.5rem 0.55rem;
  border: 1px solid transparent;
  border-radius: 10px;
  background: transparent;
  color: #cbd5e1;
  cursor: pointer;
  transition: all 0.25s ease;
  text-align: left;
  width: 100%;
}
.panel-item:hover {
  background: rgba(99, 102, 241, 0.1);
  border-color: rgba(99, 102, 241, 0.2);
  color: #e2e8f0;
  transform: translateX(-3px);
}
.panel-item-active {
  background: rgba(99, 102, 241, 0.16) !important;
  border-color: rgba(99, 102, 241, 0.35) !important;
  box-shadow: 0 0 14px rgba(99, 102, 241, 0.12);
  color: #e0e7ff !important;
}
.panel-icon { font-size: 1.15rem; flex-shrink: 0; }
.panel-text {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
}
.panel-label { font-size: 0.78rem; font-weight: 600; }
.panel-desc {
  font-size: 0.62rem;
  color: #64748b;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  transition: color 0.25s;
}
.panel-item:hover .panel-desc,
.panel-item-active .panel-desc { color: #94a3b8; }
.panel-arrow {
  width: 13px; height: 13px;
  color: #475569;
  flex-shrink: 0;
  transition: all 0.25s ease;
}
.panel-item:hover .panel-arrow,
.panel-item-active .panel-arrow {
  color: #818cf8;
  transform: translateX(3px);
}

/* ── Interaction Prompt ── */
.interact-prompt {
  position: absolute;
  bottom: 6.5rem;
  left: 50%;
  transform: translateX(-50%);
  z-index: 20;
  animation: promptSlideUp 0.35s cubic-bezier(0.16, 1, 0.3, 1);
}
@keyframes promptSlideUp {
  from { opacity: 0; transform: translateX(-50%) translateY(16px) scale(0.97); }
  to { opacity: 1; transform: translateX(-50%) translateY(0) scale(1); }
}
.prompt-card {
  position: relative;
  display: flex;
  align-items: center;
  gap: 0.9rem;
  padding: 0.85rem 1.2rem;
  overflow: hidden;
}
.prompt-glow {
  position: absolute;
  inset: -1px;
  border-radius: inherit;
  background: linear-gradient(135deg, rgba(99,102,241,0.15) 0%, transparent 50%, rgba(192,132,252,0.1) 100%);
  pointer-events: none;
}
.prompt-icon { font-size: 1.8rem; position: relative; z-index: 1; }
.prompt-info { flex: 1; position: relative; z-index: 1; }
.prompt-info strong {
  font-size: 0.92rem;
  display: block;
  color: #e0e7ff;
}
.prompt-info p {
  margin: 0.12rem 0 0;
  font-size: 0.72rem;
  color: #94a3b8;
  line-height: 1.3;
}
.prompt-btn {
  display: flex;
  align-items: center;
  gap: 0.45rem;
  padding: 0.5rem 1rem;
  border: 1px solid rgba(99, 102, 241, 0.45);
  border-radius: 9px;
  background: linear-gradient(135deg, rgba(99,102,241,0.18), rgba(139,92,246,0.18));
  color: #c7d2fe;
  font-weight: 600;
  font-size: 0.82rem;
  cursor: pointer;
  transition: all 0.2s ease;
  white-space: nowrap;
  position: relative;
  z-index: 1;
}
.prompt-btn:hover {
  background: linear-gradient(135deg, rgba(99,102,241,0.35), rgba(139,92,246,0.35));
  box-shadow: 0 0 18px rgba(99,102,241,0.2);
  transform: scale(1.04);
  border-color: rgba(129, 140, 248, 0.6);
}

/* ── Key Badge ── */
.key-badge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 24px;
  height: 24px;
  padding: 0 5px;
  background: rgba(255,255,255,0.07);
  border: 1px solid rgba(255,255,255,0.15);
  border-bottom: 2px solid rgba(255,255,255,0.12);
  border-radius: 5px;
  font-size: 0.68rem;
  font-weight: 700;
  color: #cbd5e1;
  letter-spacing: 0.02em;
}
.key-wide {
  padding: 0 8px;
  font-size: 0.65rem;
}

/* ── Instructions ── */
.instructions {
  position: absolute;
  bottom: 5.5rem;
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  align-items: center;
  gap: 1rem;
  padding: 0.7rem 1.4rem;
  z-index: 15;
  transition: opacity 1.2s ease, transform 1.2s ease;
  animation: fadeInUp 0.5s ease 0.5s both;
}
@keyframes fadeInUp {
  from { opacity: 0; transform: translateX(-50%) translateY(10px); }
  to { opacity: 1; transform: translateX(-50%) translateY(0); }
}
.instructions.fade-out {
  opacity: 0;
  transform: translateX(-50%) translateY(8px);
  pointer-events: none;
}
.instruction-item {
  display: flex;
  align-items: center;
  gap: 0.35rem;
}
.key-group {
  display: flex;
  gap: 0.2rem;
}
.inst-text {
  font-size: 0.75rem;
  color: #94a3b8;
  margin-left: 0.25rem;
  font-weight: 500;
}
.instruction-divider {
  width: 1px;
  height: 22px;
  background: rgba(255,255,255,0.08);
}

/* ── Bottom HUD ── */
.bottom-hud {
  position: absolute;
  bottom: 1rem;
  left: 50%;
  transform: translateX(-50%);
  z-index: 10;
  pointer-events: none;
  display: flex;
  align-items: center;
  gap: 0.55rem;
  padding: 0.45rem 1.4rem;
  border-radius: 50px;
  animation: fadeInUp 0.5s ease 0.8s both;
}
.hud-icon { font-size: 1rem; }
.hud-label {
  font-size: 0.75rem;
  color: #94a3b8;
  font-weight: 400;
}
.hud-label strong { color: #c7d2fe; font-weight: 600; }

/* ── Responsive ── */
@media (max-width: 768px) {
  .side-panel { display: none; }
  .top-bar { padding: 0.75rem 1rem; }
  .page-title { font-size: 1rem; }
  .back-btn span { display: none; }
  .prompt-card { flex-direction: column; text-align: center; gap: 0.5rem; padding: 1rem; }
  .prompt-info { text-align: center; }
  .instructions { gap: 0.5rem; padding: 0.6rem 1rem; }
  .instruction-divider { height: 18px; }
  .title-sub { display: none; }
}

@media (max-width: 480px) {
  .instructions { flex-direction: column; gap: 0.4rem; }
  .instruction-divider { width: 40px; height: 1px; }
}

