  font-weight: 400;
}
.hud-label strong { color: #4361ee; font-weight: 600; }

/* ═══════════════════════════════════════════
   LIBRARY BROWSER OVERLAY
   ═══════════════════════════════════════════ */
.library-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.5);
  z-index: 50;
  display: flex;
  align-items: center;
  justify-content: center;
  animation: fadeIn 0.3s ease;
}
@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

.library-browser {
  width: 90%;
  max-width: 1100px;
  max-height: 85vh;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  animation: scaleIn 0.3s cubic-bezier(0.16, 1, 0.3, 1);
  background: rgba(255, 255, 255, 0.95);
}
@keyframes scaleIn {
  from { opacity: 0; transform: scale(0.95); }
  to { opacity: 1; transform: scale(1); }
}

.library-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 1rem 1.5rem;
  border-bottom: 1px solid rgba(0, 0, 0, 0.08);
}
.library-title {
  display: flex;
  align-items: center;
  gap: 0.6rem;
}
.library-title span { font-size: 1.5rem; }
.library-title h2 {
  margin: 0;
  font-size: 1.2rem;
  font-weight: 700;
  color: #1e293b;
}
.library-actions {
  display: flex;
  align-items: center;
  gap: 0.6rem;
}
.library-visit-btn {
  padding: 0.45rem 1rem;
  border: 1px solid rgba(114, 9, 183, 0.3);
  border-radius: 8px;
  background: linear-gradient(135deg, rgba(114, 9, 183, 0.08), rgba(67, 97, 238, 0.08));
  color: #7209b7;
  font-size: 0.8rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s;
}
.library-visit-btn:hover {
  background: linear-gradient(135deg, rgba(114, 9, 183, 0.18), rgba(67, 97, 238, 0.18));
  border-color: rgba(114, 9, 183, 0.5);
}
.library-close-btn {
  width: 32px;
  height: 32px;
  border: 1px solid rgba(0, 0, 0, 0.08);
  border-radius: 8px;
  background: rgba(0, 0, 0, 0.03);
  color: #64748b;
  font-size: 1rem;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s;
}
.library-close-btn:hover {
  background: rgba(239, 68, 68, 0.08);
  border-color: rgba(239, 68, 68, 0.2);
  color: #ef4444;
}

.library-loading {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 3rem;
  gap: 1rem;
  color: #64748b;
}

.library-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
  gap: 1rem;
  padding: 1.2rem;
  overflow-y: auto;
  max-height: calc(85vh - 70px);
}

.library-card {
  background: rgba(255, 255, 255, 0.6);
  border: 1px solid rgba(0, 0, 0, 0.06);
  border-radius: 12px;
  overflow: hidden;
  cursor: pointer;
  transition: all 0.25s ease;
}
.library-card:hover {
  background: rgba(67, 97, 238, 0.04);
  border-color: rgba(67, 97, 238, 0.15);
  transform: translateY(-3px);
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.1);
}
.card-cover {
  width: 100%;
  height: 140px;
  background: linear-gradient(135deg, #e0e7ff, #f0e6ff);
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
}
.card-cover img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}
.card-cover-placeholder {
  font-size: 3rem;
  opacity: 0.25;
}
.card-info {
  padding: 0.8rem;
}
.card-type {
  display: inline-block;
  padding: 0.15rem 0.5rem;
  background: rgba(114, 9, 183, 0.08);
  border-radius: 4px;
  font-size: 0.6rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: #7209b7;
  margin-bottom: 0.4rem;
}
.card-title {
  margin: 0.3rem 0;
  font-size: 0.88rem;
  font-weight: 600;
  color: #1e293b;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
.card-author {
  margin: 0.15rem 0;
  font-size: 0.72rem;
  color: #64748b;
}
.card-desc {
  margin: 0.3rem 0;
  font-size: 0.68rem;
  color: #94a3b8;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  line-height: 1.4;
}
.card-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-top: 0.5rem;
  padding-top: 0.5rem;
  border-top: 1px solid rgba(0, 0, 0, 0.05);
}
.card-price {
  font-size: 0.82rem;
  font-weight: 700;
  color: #4361ee;
}
.card-free {
  font-size: 0.75rem;
  font-weight: 600;
  color: #10b981;
}
.card-stock {
  font-size: 0.62rem;
  color: #10b981;
  font-weight: 500;
}
.card-stock.low-stock {
  color: #f59e0b;
}
.library-empty {
  grid-column: 1 / -1;
  text-align: center;
  padding: 3rem;
  color: #94a3b8;
}

/* ── Responsive ── */
@media (max-width: 768px) {
  .side-panel { display: none; }
  .top-bar { padding: 0.75rem 1rem; }
  .page-title { font-size: 1rem; }
  .back-btn span { display: none; }
  .prompt-card { flex-direction: column; text-align: center; gap: 0.5rem; padding: 1rem; }
  .prompt-info { text-align: center; }
  .instructions { gap: 0.5rem; padding: 0.6rem 1rem; }
  .instruction-divider { height: 18px; }
  .title-sub { display: none; }
  .library-browser { width: 95%; max-height: 90vh; }
  .library-grid { grid-template-columns: repeat(auto-fill, minmax(160px, 1fr)); gap: 0.75rem; padding: 0.8rem; }
}

@media (max-width: 480px) {
  .instructions { flex-direction: column; gap: 0.4rem; }
  .instruction-divider { width: 40px; height: 1px; }
  .library-grid { grid-template-columns: 1fr; }
}
